import { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import API from "../../services/api";
import "./css/UserDashboard.css";

function UserResume() {
  const [resumeData, setResumeData] = useState(null);

  useEffect(() => {
    fetchResume();
  }, []);

  const fetchResume = async () => {
    try {
      const res = await API.get("/user/resume");
      setResumeData(res.data);
    } catch (e) {
      console.error(e);
    }
  };

  return (
    <div className="dashboard-layout">
      <aside className="dashboard-sidebar">
        <div className="sidebar-logo">
          <div className="logo-icon">RA</div>
          ResumeAlert
        </div>

        <nav className="nav-menu">
          <Link to="/user/dashboard" className="nav-link">Dashboard</Link>
          <Link to="/user/resume" className="nav-link active">My Resume</Link>
          <Link to="/user/alerts" className="nav-link">Job Alerts</Link>
          <Link to="/user/saved-jobs" className="nav-link">Saved Jobs</Link>
          <Link to="/user/account" className="nav-link">Account</Link>
        </nav>

        <div className="sidebar-footer">
          <Link to="/" style={{textDecoration: 'none'}}>
            <button className="sign-out-btn">
              Sign Out
            </button>
          </Link>
        </div>
      </aside>

      <main className="dashboard-main">
        <header className="dashboard-header-flex">
          <div className="header-titles">
            <h1>My Resume</h1>
            <p>Your currently uploaded profile and extracted skill tags.</p>
          </div>
        </header>

        {resumeData ? (
          <div className="update-resume-card hover-lift" style={{maxWidth: '800px'}}>
             <div style={{display: 'flex', alignItems: 'center', gap: '1rem', borderBottom: '1px solid var(--border-color)', paddingBottom: '1.5rem', marginBottom: '1.5rem'}}>
                <div style={{width: '64px', height: '64px', background: 'var(--primary-light)', color: 'var(--primary-color)', borderRadius: 'var(--radius-md)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '2rem', fontWeight: 700}}>
                  RP
                </div>
                <div>
                  <h2 style={{color: 'var(--text-primary)', fontSize: '1.25rem'}}>{resumeData.name}'s Primary Resume</h2>
                  <p style={{color: 'var(--text-secondary)', fontSize: '0.8rem'}}>Last updated: Just now</p>
                </div>
             </div>

             <div className="extracted-profile" style={{marginTop: 0}}>
                <div className="ep-title">EXTRACTED PROFILE</div>
                <div className="badges-row">
                  {resumeData.skills && resumeData.skills.map((s, i) => (
                     <span key={i} className="tech-badge">{s}</span>
                  ))}
                </div>
             </div>

             <div className="cgpa-row">
                <div className="cgpa-label">System Verified CGPA:</div>
                <div className="cgpa-value">{resumeData.cgpa || "N/A"}</div>
             </div>
          </div>
        ) : (
          <p>Loading resume details...</p>
        )}
      </main>
    </div>
  );
}

export default UserResume;
